-- ============================================================
-- AIHKYA: Tool Content Fields
-- Adds features, pros, cons, use_cases, alternatives,
-- hindi_summary, screenshot_url to ai_tools
-- Migration 0010
-- ============================================================

ALTER TABLE public.ai_tools
  ADD COLUMN IF NOT EXISTS features      JSONB DEFAULT '{"en":[],"hi":[],"hinglish":[]}',
  ADD COLUMN IF NOT EXISTS pros          JSONB DEFAULT '{"en":[],"hi":[],"hinglish":[]}',
  ADD COLUMN IF NOT EXISTS cons          JSONB DEFAULT '{"en":[],"hi":[],"hinglish":[]}',
  ADD COLUMN IF NOT EXISTS use_cases     JSONB DEFAULT '{"en":[],"hi":[],"hinglish":[]}',
  ADD COLUMN IF NOT EXISTS alternatives  TEXT[]  DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS hindi_summary TEXT,
  ADD COLUMN IF NOT EXISTS screenshot_url VARCHAR(500);


-- ── ChatGPT ──────────────────────────────────────────────────────────────────
UPDATE public.ai_tools SET
  features = '{"en":["Multi-turn conversations with memory","Code writing, review and debugging","Image analysis and generation (GPT-4o)","Voice conversation mode","Math, logic and data analysis","PDF and document reading","40+ language support including Hindi"],"hi":["मेमोरी के साथ बहु-बारी बातचीत","कोड लिखना, समीक्षा और डीबगिंग","इमेज विश्लेषण और निर्माण (GPT-4o)","वॉइस बातचीत मोड","गणित, तर्क और डेटा विश्लेषण","PDF और दस्तावेज़ पढ़ना","हिंदी सहित 40+ भाषाओं का समर्थन"],"hinglish":["Memory ke saath multi-turn conversations","Code likhna, review aur debugging","Image analysis aur generation (GPT-4o)","Voice conversation mode","Math, logic aur data analysis","PDF aur document reading","Hindi sametan 40+ languages ka support"]}',
  pros = '{"en":["Handles almost any task — most versatile AI available","Best-in-class conversational understanding","Strong coding and debugging assistant","Generous free tier with GPT-4o access","Massive plugin and integration ecosystem"],"hi":["लगभग कोई भी काम — सबसे बहुमुखी AI","बेहतरीन बातचीत की समझ","मजबूत कोडिंग असिस्टेंट","उदार मुफ्त टियर GPT-4o के साथ","विशाल प्लगइन और इंटीग्रेशन इकोसिस्टम"],"hinglish":["Almost koi bhi kaam — sabse versatile AI","Best-in-class conversational understanding","Strong coding aur debugging assistant","Generous free tier GPT-4o ke saath","Massive plugin aur integration ecosystem"]}',
  cons = '{"en":["Free tier has daily usage limits","Can state wrong facts confidently (hallucination)","No real-time web access on free plan","Hindi output quality can be inconsistent"],"hi":["मुफ्त टियर में दैनिक उपयोग की सीमा","कभी-कभी गलत जानकारी आत्मविश्वास से देता है","मुफ्त प्लान में रियल-टाइम वेब नहीं","हिंदी आउटपुट कभी-कभी असंगत हो सकता है"],"hinglish":["Free tier mein daily usage limits","Kabhi kabhi galat facts confidently bolta hai","Free plan pe real-time web access nahi","Hindi output kabhi kabhi inconsistent ho sakta hai"]}',
  use_cases = '{"en":["Writing blogs, emails and social media content","Coding help and debugging for developers","Business planning, analysis and reports","Answering complex academic or research questions","Customer support script and template creation","Quick learning of new subjects or skills"],"hi":["ब्लॉग, ईमेल और सोशल मीडिया कंटेंट लिखना","डेवलपर्स के लिए कोडिंग और डीबगिंग","बिज़नेस प्लानिंग, विश्लेषण और रिपोर्ट","जटिल अकादमिक या शोध सवालों के जवाब","कस्टमर सपोर्ट स्क्रिप्ट और टेम्पलेट","नए विषय या कौशल तेज़ी से सीखना"],"hinglish":["Blog, email aur social media content likhna","Developers ke liye coding aur debugging","Business planning, analysis aur reports","Complex academic ya research sawaalon ke jawaab","Customer support scripts aur templates banana","Naye subjects ya skills seekhna"]}',
  alternatives = ARRAY['claude','gemini','perplexity-ai','microsoft-copilot','meta-ai'],
  hindi_summary = 'ChatGPT भारत में सबसे ज़्यादा इस्तेमाल होने वाला AI टूल है। यह हिंदी में कंटेंट लिखने, सवाल-जवाब करने, कोडिंग और बिज़नेस प्लानिंग — सभी कामों में उपयोगी है। मुफ्त वर्शन में भी GPT-4o का उपयोग होता है और ज़्यादातर काम हो जाता है।'
WHERE slug = 'chatgpt';


-- ── Claude ───────────────────────────────────────────────────────────────────
UPDATE public.ai_tools SET
  features = '{"en":["200K token context window (longest available)","Superior document analysis and summarization","Nuanced creative writing and editing","Strong coding across 20+ languages","Thoughtful and safe AI responses","File uploads: PDF, Word, code files","Multilingual support including Hindi"],"hi":["200K टोकन कॉन्टेक्स्ट विंडो (सबसे लंबा)","बेहतरीन दस्तावेज़ विश्लेषण और सारांश","सूक्ष्म क्रिएटिव लेखन और संपादन","20+ भाषाओं में मजबूत कोडिंग","विचारशील और सुरक्षित AI जवाब","PDF, Word, कोड फाइलें अपलोड करें","हिंदी सहित बहुभाषी समर्थन"],"hinglish":["200K token context window (sabse lamba)","Superior document analysis aur summarization","Nuanced creative writing aur editing","20+ languages mein strong coding","Thoughtful aur safe AI responses","PDF, Word, code files upload karo","Hindi sametan multilingual support"]}',
  pros = '{"en":["Best for long document analysis (books, contracts, reports)","More thoughtful and nuanced than competitors","Excellent coding assistant with explanations","Honest about its limitations","Strong privacy commitment from Anthropic"],"hi":["लंबे दस्तावेज़ विश्लेषण के लिए सबसे अच्छा","प्रतिस्पर्धियों से अधिक विचारशील और सूक्ष्म","बेहतरीन कोडिंग असिस्टेंट","अपनी सीमाओं के बारे में ईमानदार","Anthropic की मजबूत गोपनीयता प्रतिबद्धता"],"hinglish":["Long documents ke liye best (books, contracts, reports)","Competitors se zyada thoughtful aur nuanced","Excellent coding assistant with explanations","Apni limitations ke baare mein honest","Anthropic ki strong privacy commitment"]}',
  cons = '{"en":["No image generation capability","Slower response speed on free tier","Limited integrations compared to ChatGPT","Less popular in India — fewer Hindi tutorials"],"hi":["इमेज बनाने की क्षमता नहीं","मुफ्त टियर पर धीमी प्रतिक्रिया गति","ChatGPT की तुलना में कम इंटीग्रेशन","भारत में कम लोकप्रिय — कम हिंदी ट्यूटोरियल"],"hinglish":["Image generation capability nahi hai","Free tier pe slow response speed","ChatGPT ke comparison mein kam integrations","India mein kam popular — kam Hindi tutorials"]}',
  use_cases = '{"en":["Analyzing lengthy legal contracts or financial reports","Academic research paper reading and summarization","Long-form content writing (books, manuals)","Complex coding projects and architecture review","Business document drafting with high accuracy","Deep research on any topic"],"hi":["लंबे कानूनी अनुबंध या वित्तीय रिपोर्ट का विश्लेषण","अकादमिक शोध पत्र पढ़ना और सारांश बनाना","लंबे-फॉर्म कंटेंट लेखन (पुस्तकें, मैनुअल)","जटिल कोडिंग प्रोजेक्ट और आर्किटेक्चर समीक्षा","उच्च सटीकता के साथ व्यापार दस्तावेज़","किसी भी विषय पर गहन शोध"],"hinglish":["Lambe legal contracts ya financial reports ka analysis","Academic research papers padhna aur summarize karna","Long-form content likhna (books, manuals)","Complex coding projects aur architecture review","High accuracy ke saath business documents banana","Kisi bhi topic pe deep research"]}',
  alternatives = ARRAY['chatgpt','gemini','perplexity-ai','microsoft-copilot'],
  hindi_summary = 'Claude लंबे दस्तावेज़ पढ़ने और विश्लेषण करने में सबसे अच्छा AI है। अगर आपके पास बड़ी PDF, कानूनी दस्तावेज़, या रिसर्च पेपर हैं, तो Claude उन्हें आसानी से समझ सकता है। यह ChatGPT से ज़्यादा सावधान और विश्वसनीय जवाब देता है।'
WHERE slug = 'claude';


