  pros = '{"en":["Every answer cites real sources you can verify","Best AI for research and fact-checking","No hallucination risk — grounded in real web results","Excellent for current events and news","Free tier is generous with web search"],"hi":["हर जवाब असली स्रोत उद्धृत करता है जिसे आप सत्यापित कर सकते हैं","रिसर्च और फैक्ट-चेकिंग के लिए सबसे अच्छा AI","हेल्यूसिनेशन का कम जोखिम — असली वेब परिणामों पर आधारित","वर्तमान घटनाओं और समाचार के लिए बेहतरीन","मुफ्त टियर में वेब सर्च उदार है"],"hinglish":["Har jawab real sources cite karta hai jo verify kar sako","Research aur fact-checking ke liye best AI","Hallucination ka kam risk — real web results pe grounded","Current events aur news ke liye excellent","Free tier mein generous web search"]}',
  cons = '{"en":["Not ideal for creative writing or long-form content","Hindi interface and results less refined","Limited conversation memory compared to ChatGPT","Pro plan needed for unlimited searches"],"hi":["क्रिएटिव लेखन या लंबे-फॉर्म कंटेंट के लिए आदर्श नहीं","हिंदी इंटरफेस और परिणाम कम परिष्कृत","ChatGPT की तुलना में सीमित बातचीत मेमोरी","असीमित खोज के लिए Pro प्लान चाहिए"],"hinglish":["Creative writing ya long-form content ke liye ideal nahi","Hindi interface aur results kam refined","ChatGPT ke comparison mein limited conversation memory","Unlimited searches ke liye Pro plan chahiye"]}',
